const e={INTRO:{title:"依頼",lines:[{speaker:"Delphine",text:"農園の地図を持っていますが、今のところ研究室という場所しか把握していません。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"I have been provided with photos of everyone who was known to be present on the premises at the time.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"しかし、私のパトロンの父と妹の名前しか持っていません。他のゲストの名前を知る必要があります。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"そうですね。研究室に行ってみましょう。何か手がかりがあるかもしれません。",portrait:"portraits/investigator.png"}]},STUDY_ZERO:{title:"残留する記憶",lines:[{speaker:"Delphine",text:"集中すると、研究室の本質を感じることができます。まるで自分がその部屋にいるようです。その感覚は言葉では説明しがたく、多くの人はこれが現実ではなく、ただのトリックだと思っています。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"古い部屋には独特の雰囲気があります。その空間の本質を形成するものが部屋の一部となるのです。長く存在するアイテムは、その空間に根付くようになります。",portrait:"portraits/investigator.png"}]},PHONE_TIP:{title:"注入されたアイテム",lines:[{speaker:" ",text:"デルフィーヌはここの電話のようなアイテムに集中することができます。"},{speaker:" ",text:"インベントリのアイテム画面で電話に行き、正しい所有者を帰属させることで調整できます（または、どこからでもiを押してください）。"},{speaker:" ",text:"所有者が特定されると、デルフィーヌはいつでもそのアイテムを使用している人のオーラを感じることができ、その存在で何が起こったかのエコーを見ることができます。"},{speaker:"Delphine",text:"ジェレマイアは農園の所有者なので、彼が最も頻繁に電話を使用している可能性が高く、彼に調整する必要があるでしょう。",portrait:"portraits/investigator.png"}]},LINES:{lines:[{speaker:"Delphine",text:"臨時の軍営地は「the lines」と呼ばれ、テントではなく、現地の資材で作られた小屋が並んでいました。",portrait:"portraits/investigator.png"}]},STUDY_ONE:{title:"書斎の残響",lines:[{speaker:"Delphine",text:"16時にジェレマイアが書斎で一人だったことは分かっています。ジェレマイアに強く意識を集中すれば、そこで起きた出来事の残響が見えるはずです。",portrait:"portraits/investigator.png"},{speaker:" ",text:"タイムラインを16:00に設定し、ジェレマイアの写真を焦点に置いてください。"},{speaker:" ",text:"客は同じ時間に一つの場所にしか存在できません。ある場所で客を見かけたなら、その人物は同時刻に別の場所にはいません。"}]},LIBRARY_WARNING:{title:"不足している証拠",lines:[{speaker:"Delphine",text:"図書室で新たな発見をするには、まだ証拠が足りません。今はひとまず、予期せぬ来客の到着に集中すべきでしょう。",portrait:"portraits/investigator.png"}]},STUDY_11:{title:"電話",branches:[{check:t=>!t.unlockedPeople.has("p10"),lines:[{speaker:"Delphine",text:"カナンと一緒にジロウという人物がこの部屋にいます。彼が誰なのか突き止めたら、またここへ戻って彼側からの会話を見てみるべきでしょう。",portrait:"portraits/investigator.png"}]},{check:t=>t.unlockedPeople.has("p10"),lines:[{speaker:"Delphine",text:"ここにジロウとカナンの両方が書斎にいたことが分かりました。二人に同時に意識を集中すれば、この残響を完全に解放できるはずです。",portrait:"portraits/investigator.png"}]}]},STUDY_11_2:{title:"電話",lines:[{speaker:"Delphine",text:"カナンと一緒にジロウという人物がこの部屋にいます。彼が誰なのか突き止めたら、またここへ戻って彼側からの会話を見てみるべきでしょう。",portrait:"portraits/investigator.png"}]},DEDUCTION_HELP:{title:"新たな手がかり",lines:[{speaker:"Delphine",text:"見知らぬ二人……写真も名前も揃いました。ボルネオの先住民には姓を持たない人々も多いことを忘れてはいけません。つまり、カナンは名前だけで特定できるはずです。",portrait:"portraits/investigator.png"},{speaker:" ",text:"デルフィーヌが状況証拠から人物を特定できれば、「Guests」の事件ファイルで顔に名前を割り当てられます。"}]},TELEPHONE_0:{title:"手回し式電話",lines:[{speaker:"Delphine",text:"この電話には強い残留思念があります。午前2時に、ボルネオ訛りのある男がこれを使っている感覚をはっきり感じ取れます。",portrait:"portraits/investigator.png"},{speaker:" ",text:"デルフィーヌは電話に宿るオーラを捉えたため、どの時間帯であっても、それを使用している人物を感じ取れるようになりました。"},{speaker:" ",text:"ただし、感じ取れるのはその品物を使っている、あるいは持っている人物だけであり、同じ部屋にいる他の人物までは感知できません。"}]},GHOST_IMAGE:{title:"幽霊像",lines:[{speaker:"Delphine",text:"なんてこと……！ あの閃光……鏡に映ったあの像は……",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"かすかでしたが、あれは間違いなく強い精神痕跡です。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"あの閃光の凄まじさが、エーテルに痕跡を刻み残したのでしょう。追跡するには十分な強さです。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"この錨となる痕跡があれば、彼を追えます。今なら、農園内を移動する彼の気配を感じ取れます。",portrait:"portraits/investigator.png"}]},SHAMAN_NAME:{title:"シャーマン",lines:[{speaker:"Delphine",text:"ババリアン・アンタウ……強力なシャーマンです。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"彼の写真を見つけることはおそらくできないでしょう。あまりにも無名で、歴史の闇に埋もれた存在です。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"別の方法で彼の存在を推理するしかありません。彼の足取りを繋ぎ合わせるには、常識に囚われない考え方が必要になりそうです。",portrait:"portraits/investigator.png"}]},TUAN_BESAR:{title:"トゥアン",theme:"british_standards",lines:[{speaker:"Delphine",text:"こうした農園では、《トゥアン》は役職者への一般的な呼称です。《トゥアン・ブサール》、つまり《大旦那様》は、農園全体を統括する最高責任者を指します。この場合、カナンが言っているのはジェレマイア・グッドウィルのことです。",portrait:"portraits/investigator.png"}]},MEM:{title:"メム",theme:"british_standards",lines:[{speaker:"Delphine",text:"《メム》は《屋敷の奥様》を指す特別な呼称です。《リトル・メム》というのは、使用人たちがリュンを親しみを込めて呼ぶ際の愛称なのでしょう。",portrait:"portraits/investigator.png"}]},CONSTABULARY:{title:"警察隊",theme:"maritime_rules",lines:[{speaker:"Delphine",text:"北ボルネオ武装警察隊の海上部門は、イギリス領北ボルネオにおける沿岸警備隊に最も近い存在です。日本軍侵攻以前は、小型武装モーターランチを運用し、沿岸の巡回を行っていました。",portrait:"portraits/investigator.png"}]},PIRACY_GRILLE:{theme:"piracy",title:"防盗格子",lines:[{speaker:"Delphine",text:"海賊による船乗っ取りの脅威はあまりにも一般的だったため、1920年代の蒸気船には防盗格子が備え付けられていました。重い鉄格子や扉によって艦橋や一等客室を船内の他区画から隔離し、士官区画そのものを要塞のようにしていたのです。",portrait:"portraits/investigator.png"}]},GAYUNG:{title:"ガユン",theme:"british_standards",lines:[{speaker:"Delphine",text:"ガユンとは、水浴びの際に水瓶や桶から水をすくうために使われる、伝統的な柄杓状の道具です。通常はプラスチック製または金属製です。",portrait:"portraits/investigator.png"}]},SHANGAI_JAR:{title:"上海壺",theme:"british_standards",lines:[{speaker:"Delphine",text:"大型の陶製《上海壺》は、熱帯の暑さの中で水浴び用の冷水を保管するため、植民地時代の住宅で一般的に使われていました。",portrait:"portraits/investigator.png"}]},FEVER:{title:"熱病",theme:"tropical_killers",lines:[{speaker:"Delphine",text:"リュンが言っているのはブラックウォーター熱のことでしょう。熱帯地域において若いヨーロッパ人に最も恐れられていた死因です。繰り返されるマラリア感染によって引き起こされる恐ろしい合併症で、数日以内に命を落とすことも珍しくありません。",portrait:"portraits/investigator.png"}]},STARCHED_WHITES:{title:"糊の効いた白服",theme:"british_standards",lines:[{speaker:"Delphine",text:"糊の効いた白服は、植民地の邸宅における男性たちの標準的な装いです。白い半ズボン、白いハイソックス、白いシャツを糊でぱりっと仕上げ、清潔に整え、しばしばラベンダーなどの香りを漂わせています。労働にはまったく不向きですが、イギリス人としての優越性という時代錯誤な幻想を保つために着用されていました。",portrait:"portraits/investigator.png"}]},SABAH:{title:"サバ",theme:"colonies",lines:[{speaker:"Delphine",text:"サバはボルネオ最大の州です。西にはサラワクとカリマンタン、東にはフィリピンが接しています。19世紀にイギリス政府から王室特許を与えられた民間企業、《イギリス領北ボルネオ会社》によって統治されていました。",portrait:"portraits/investigator.png"}]},SUNDOWNER:{title:"サンダウナー",theme:"culture",lines:[{speaker:"Delphine",text:"調査によれば、《サンダウナー》とは、日中の暑さから夕方の涼しさへの移り変わりを祝うため、日没時に飲む一杯を指す現地の俗称です。",portrait:"portraits/investigator.png"}]},GIN_PAHITS:{title:"ジン・パヒ",theme:"culture",lines:[{speaker:"Delphine",text:"ジン・パヒとは、ジンにアンゴスチュラ・ビターズをたっぷり加えた飲み物です。蒸し暑いジャングルで一日を過ごした後の胃を落ち着かせる効果があると考えられていました。",portrait:"portraits/investigator.png"}]},SMALL_CHOPS:{title:"スモール・チョップス",theme:"culture",lines:[{speaker:"Delphine",text:"スモール・チョップスとは、サンダウナーと一緒に供される軽食の現地呼称です。塩気や香りを強くして味覚を刺激し、酒が進むように作られていました。",portrait:"portraits/investigator.png"}]},TOBACCO_TRADE_IS_DRYING_UP:{title:"タバコ産業の衰退",theme:"colonies",lines:[{speaker:"Delphine",text:"30年前の北ボルネオは、高品質なシガー用ラッパー葉で世界的に知られていました。しかし1930年代になると、紙巻き煙草の流行と土壌疲弊の影響で、多くのタバコ会社が事業を縮小するか、ゴムやココナッツ産業へ転換し始めました。どうやらグッドウィル家は時流に乗り遅れ、その圧力を強く受けていたようです。",portrait:"portraits/investigator.png"}]},BAJAU:{title:"バジャウ族",theme:"pearls",lines:[{speaker:"Delphine",text:"バジャウ族は、ボルネオ周辺の海域で暮らす遊牧的な海洋民族です。卓越した潜水技術を持ち、真珠に関する深い知識で知られています。",portrait:"portraits/investigator.png"}]},TOWKAY:{title:"トウケイ",theme:"pearls",lines:[{speaker:"Delphine",text:"中国系トウケイとは、戦前の北ボルネオで真珠取引を支配していた、強い影響力を持つ有力商人たちのことです。",portrait:"portraits/investigator.png"}]},KORNBRAND:{title:"コルンブラント",theme:"culture",lines:[{speaker:"Delphine",text:"コルンブラントはドイツの穀物蒸留酒で、ウォッカに非常によく似ていますが、穀物の風味を残すため、やや低めの度数で蒸留されることが多い酒です。イギリス人から見ればウォッカのように映るでしょうが、ドイツ人やロシア人にとって、その違いは非常に重要なのです。",portrait:"portraits/investigator.png"}]},SUNNING:{title:"サニング号",theme:"piracy",lines:[{speaker:"Delphine",text:"サニング号は、1926年に海賊によって乗っ取られた蒸気船です。",portrait:"portraits/investigator.png"}]},TUAN_DOSE:{title:"旦那様の薬",theme:"tropical_killers",lines:[{speaker:"Delphine",text:"キニーネは空腹時に服用すべきではないと考えられていたため、通常はサンダウナーと夕食前の軽食と共に毎日摂取されていました。ボルネオでは、ほとんど誰もがマラリア予防のために毎日服用していました。",portrait:"portraits/investigator.png"}]},QUININE:{title:"キニーネ",theme:"tropical_killers",lines:[{speaker:"Delphine",text:"キニーネは空腹時に服用すべきではないと考えられていたため、通常はサンダウナーと夕食前の軽食と共に毎日摂取されていました。ボルネオでは、ほとんど誰もがマラリア予防のために毎日服用していました。",portrait:"portraits/investigator.png"}]},SALLOW:{title:"土気色",theme:"tropical_killers",lines:[{speaker:"Delphine",text:"《サロー》とは、マラリアに感染したヨーロッパ人の顔や手に現れる黄ばんだ肌色を指す表現です。慢性的な病の兆候とされていました。",portrait:"portraits/investigator.png"}]},BIAS_BAY:{title:"バイアス湾",theme:"piracy",lines:[{speaker:"Delphine",text:"バイアス湾は広東沿岸にある隠れ入り江で、海賊黄金時代には海賊たちの共和国として機能していました。",portrait:"portraits/investigator.png"}]},STRAITS_STEAMSHIP:{title:"海峡汽船",theme:"the_seas",lines:[{speaker:"Delphine",text:"海峡汽船は、グッドウィル家が本土とボルネオの間で物資や人員を輸送するために利用していた主要航路です。定期航路ではありましたが、同時に海賊たちの格好の標的でもありました。",portrait:"portraits/investigator.png"}]},SANDAKAN:{title:"サンダカン",theme:"colonies",lines:[{speaker:"Delphine",text:"サンダカンはイギリス領北ボルネオの首都であり、この地域最大の都市でした。洗練されたイギリス式行政都市である一方、その周囲には広大で危険なジャングルと無法の海が広がる、極端な対比を抱えた場所でもありました。終戦までには完全に破壊されています。",portrait:"portraits/investigator.png"}]},KACHANG:{theme:"culture",lines:[{speaker:"Delphine",text:"《カチャン》はマレー語で《豆》や《ナッツ》を意味します。通常は香辛料と共に炒ったピーナッツを指します。",portrait:"portraits/investigator.png"}]},BLACK_SMOKE:{theme:"japanese_invasion",lines:[{speaker:"Delphine",text:"日本軍侵攻が目前に迫った際、オランダ軍は製油所を爆破し、ミリおよびバリクパパンの油井に火を放ちました。その結果、数週間にわたりボルネオの空は黒煙に覆われていたのです。",portrait:"portraits/investigator.png"}]},CHANDU:{theme:"opium",lines:[{speaker:"Delphine",text:"チャンドゥは精製アヘンの一種で、煮詰めて発酵させた糖蜜状のペーストです。多くの植民地では政府専売品として扱われていました。",portrait:"portraits/investigator.png"}]},DROSS:{theme:"opium",lines:[{speaker:"Delphine",text:"ドロスとは、アヘンを吸引した後に残る炭のような有毒残留物のことです。しばしば掻き集められ、新しいアヘンに混ぜ直されたり、精製チャンドゥを買えない常習者によって消費されていました。",portrait:"portraits/investigator.png"}]},LAMP:{lines:[{speaker:"Delphine",text:"ティリーランプ。イギリス植民地で標準的に使われていた加圧式パラフィンランプです。",portrait:"portraits/investigator.png"}]},KOTA_BHARU:{title:"コタ・バル",lines:[{speaker:"Delphine",text:"マラヤ北東部のコタ・バルは、極めて重要な軍事拠点であり、太平洋戦争最初の大規模戦闘が行われた場所です。",portrait:"portraits/investigator.png"}]},RUNDUM_REBELLION:{title:"ルンドゥム蜂起",theme:"colonies",lines:[{speaker:"Delphine",text:"1915年のルンドゥム蜂起は、ムルット族によるイギリス領北ボルネオ会社への最後の大規模反乱でした。会社による課税政策と強制労働が引き金となったのです。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"吹き矢《スンピタン》で知られるムルット族は、内陸の密林に精巧な地下要塞を築いていました。若い植民地将校たちにとって、敵地で姿の見えない相手と戦うことは恐怖そのものでした。",portrait:"portraits/investigator.png"}]},TUJU:{title:"トゥジュ",theme:"occult",lines:[{speaker:"Delphine",text:"トゥジュとは、ボモーと呼ばれる呪術師が、魔術によって物体を犠牲者の体内へ送り込み、死に至らしめる呪いです。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"犠牲者は突然、原因不明の激痛――《刺すような痛み》や《震え》――に苦しみますが、西洋医学では異常を発見できません。心理的恐怖と根深い迷信が結び付いた、極めて恐ろしい概念です。",portrait:"portraits/investigator.png"}]},PIRATE_CAPTAIN:{title:"海賊船長",lines:[{speaker:"Delphine",text:"（心の声）あの男……ルートヴィヒ・ハロウ。まるで王のような振る舞いをしていた。ありふれた盗賊ではない。新聞に載るほど悪名高い人物なのかしら？",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"（心の声）どのみち電話の遭難信号についてアルマンに連絡する必要があるわ。ついでにハロウ船長についても記録を調べてもらいましょう。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"（電話）アルマン？ デルフィーヌよ。よく聞いて。農園から発信されたマレー語の通話を音写した記録があるの。翻訳してもらえるかしら？ 《……グッドウィル……マティ……ブリティッシュ……ネイビー……》？",portrait:"portraits/investigator.png"},{speaker:"Armand",text:"（電話越し）デルフィーヌ……はぁ。私のマレー語も鈍っているが、“mati” は《死》を意味する。どうやらジェレマイア・グッドウィルが海賊に殺害されたと主張し、イギリス海軍へ即時支援を要請していたようだ。到着予定は翌朝9時だったらしい。",portrait:"portraits/armand.jpeg"},{speaker:"Delphine",text:"手際がいいわね。虐殺が起きたかのように演出して、迅速かつ致命的な対応を引き出そうとしたわけだ。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"もうひとつ頼みがあるの。かなり奇妙に聞こえるでしょうけど、聞いてちょうだい。この海賊たちの首領はルートヴィヒ・ハロウという男だったの。どこかに彼についての情報が残っていないかと思って。",portrait:"portraits/investigator.png"},{speaker:"Armand",text:"（電話越し）ハロウ？ 驚いたな。彼は伝説的人物だ、デルフィーヌ。海賊としてではなく、戦争でな。日本軍占領に対するゲリラ部隊を率い、サンダカン死の行進から何百人もの人々を救った。",portrait:"portraits/armand.jpeg"},{speaker:"Armand",text:"（電話越し）歴史書では英雄として扱われている。そんな男が、若き日に悪役を演じていたとは……実に興味深い。公文書館に彼の軍務写真がある。そちらへ送ろう。",portrait:"portraits/armand.jpeg",action:"unlock_p13"},{speaker:"Delphine",text:"信じられない……本当にありがとう、アルマン。",portrait:"portraits/investigator.png"}]},EPILOGUE:{title:"事件解決",lines:[{speaker:"Delphine",text:"ついに成し遂げました、グッドウィル様。真実はついに白日の下に晒されたのです。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"あなたの妹リュンは炎に呑まれてなどいませんでした。あの夜を生き延び、農園から脱出したのです。そして私は、彼女がこのイングランドで新たな人生を見つけていることを願っています。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"この真実が、あなたが長年求め続けていた安らぎをもたらすことを願っています。ご希望であれば、これで事件を終わらせることもできます。ですが、まだ解き明かされていないことが残されていると私は感じています。",portrait:"portraits/investigator.png",action:"credits"}]},IRON_ROAD:{title:"鉄路",theme:"colonies",lines:[{speaker:"Delphine",text:"北ボルネオ鉄道は、極めて英国的な事業でした。島全体で唯一の鉄道網だったのです。沿岸部の農園は、この鉄道へ接続することを前提として設計されていました。また、この鉄道はサンダカン港との間で物資を輸送するためにも利用されていました。",portrait:"portraits/investigator.png"}]},BROOKE_RAJAHS:{title:"ブルック王朝",theme:"colonies",lines:[{speaker:"Delphine",text:"イギリス領ボルネオは三つの地域に分かれていました。《白人王》として知られるブルック家が統治するサラワク、イギリス領北ボルネオ会社が支配するイギリス領北ボルネオ、そしてスルタンがなお統治権を保持していたイギリス保護領ブルネイです。",portrait:"portraits/investigator.png"}]},HALE_ROCKETS:{title:"ヘイル・ロケット",theme:"japanese_invasion",lines:[{speaker:"Delphine",text:"ヘイル・ロケットはイギリスで開発されたロケット兵器群です。地上から発射され、日本軍陣地への攻撃に使用されました。非常に強力な兵器であり、多くの戦闘でイギリス軍に運用されていました。",portrait:"portraits/investigator.png"}]},TRIAD:{title:"三合会",theme:"opium",lines:[{speaker:"Delphine",text:"中国系の三合会は、ボルネオにおいて高度に組織化された犯罪組織であり、島の闇経済を支配していました。",portrait:"portraits/investigator.png"}]},BOMOH:{title:"ボモー",theme:"occult",lines:[{speaker:"Delphine",text:"ボモーとは、ボルネオにおける霊的かつ医術的役割を担うシャーマンです。深い敬意を集める存在であり、病人や負傷者の治療だけでなく、さまざまな呪術儀式のためにも呼ばれていました。",portrait:"portraits/investigator.png"}]},JOURNEY_INTRO:{title:"強まる幻視",lines:[{speaker:"Delphine",text:"記憶の網は完成した。共鳴が強まっていくのを感じる……意識が島の外へと引きずられていく。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"生存者たち――ルーカス、リュン、そしてローズ。彼らの辿った道が見える。ただ逃げ延びただけではない。彼らは、イングランドへ戻るまでの長く過酷な旅を耐え抜いたのだ。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"新たな経路が開かれた。彼らの帰還航路を示している。これで海を越えて彼らを追うことができる。",portrait:"portraits/investigator.png"}]},COLLYER_QUAY:{title:"コリア・キー",lines:[{speaker:"Delphine",text:"コリア・キーはシンガポールの活気あふれる地区です。交易と商業の中心地であり、通りには商店や市場が立ち並んでいます。",portrait:"portraits/investigator.png"}]},SAILORS_HOME:{title:"船員宿舎",lines:[{speaker:"Delphine",text:"セイラーズ・ホームは、船員たちのための宿泊施設です。",portrait:"portraits/investigator.png"}]},BOLSTER:{title:"抱き枕",lines:[{speaker:"Delphine",text:"熱帯地域で一般的に使われている、細長く硬めの枕です。",portrait:"portraits/investigator.png"}]},ULU:{title:"ウル",lines:[{speaker:"Delphine",text:"ウルとは、ボルネオの奥地に広がる深い熱帯雨林を指します。",portrait:"portraits/investigator.png"}]},CAUSEWAY:{title:"コーズウェイ",lines:[{speaker:"Delphine",text:"コーズウェイは、シンガポールとマレーシアを結ぶ橋です。",portrait:"portraits/investigator.png"}]},DBS:{title:"DBS",lines:[{speaker:"Delphine",text:"DBS（Distressed British Subject）とは、日本軍占領から逃れてきた、支援手段を持たないイギリス人難民に対する公式区分です。",portrait:"portraits/investigator.png"}]},MALACCA:{title:"マラッカ海峡",lines:[{speaker:"Delphine",text:"マレー半島とインドネシアのスマトラ島を隔てる、細長い海域です。",portrait:"portraits/investigator.png"}]},IPOH:{title:"イポー",lines:[{speaker:"Delphine",text:"侵攻初期に陥落した、マラヤの主要都市です。",portrait:"portraits/investigator.png"}]},KEDAH:{title:"ケダ州",lines:[{speaker:"Delphine",text:"ケダ州は、タイと国境を接するマレー半島北西部の州です。1941年12月下旬、この地はイギリス軍にとって戦略的大敗の舞台となりました。日本軍がマラヤ本土へ最初に侵攻した地域であり、その上陸は12月8日、真珠湾攻撃からわずか数時間後のことでした。",portrait:"portraits/investigator.png"}]},BETTY:{title:"ベティ",lines:[{speaker:"Delphine",text:"マラッカ海峡を哨戒していた日本軍双発爆撃機に対する、連合軍側のコードネームです。",portrait:"portraits/investigator.png"}]},NELL:{title:"ネル",lines:[{speaker:"Delphine",text:"マラヤ半島とインドネシアのスマトラ島を隔てる、細長い海域です。",portrait:"portraits/investigator.png"}]},GALLEFACE:{title:"ゴール・フェイス",lines:[{speaker:"Delphine",text:"ゴール・フェイスは、セイロンのコロンボにおいて最も格式高く象徴的な名所でした。広大な海辺の遊歩道《ゴール・フェイス・グリーン》と、由緒ある《ゴール・フェイス・ホテル》の二つを中心に構成されています。ルーカスにとって、ゴール・フェイスは文明世界へ戻ったと初めて実感できる場所だったのでしょう。",portrait:"portraits/investigator.png"}]},DUFF:{title:"ダフ",lines:[{speaker:"Delphine",text:"ダフとは、クリスマスプディングを指す俗称です。",portrait:"portraits/investigator.png"}]},JAGA:{title:"ジャガ",lines:[{speaker:"Delphine",text:"警備責任者。",portrait:"portraits/investigator.png"}]},FIFTH_COLUMN:{title:"第五列",theme:"japanese_invasion",lines:[{speaker:"Delphine",text:"《第五列》とは、第二次世界大戦中に連合国側で行われた枢軸国の諜報・破壊工作活動を指す呼称です。連合軍の士気や機能を内部から崩そうとする試みを表す言葉として使われました。",portrait:"portraits/investigator.png"}]},SIS:{title:"SIS",lines:[{speaker:"Delphine",text:"秘密情報部（SIS）は、イギリス初の対外情報機関です。1909年に設立され、主にドイツやソビエト連邦など外国勢力に関する情報収集、および第五列活動の監視を担っていました。後にMI6と呼ばれるようになります。",portrait:"portraits/investigator.png"}]},SECRETARIAT:{title:"植民地官房",lines:[{speaker:"Delphine",text:"総督に代わって政府運営を担っていた文官機関です。1941年当時のシンガポールでは、出国ビザ、渡航許可証、そして難民向け緊急資金に関する最終決定権を持っていました。",portrait:"portraits/investigator.png"}]},SUMATRA:{title:"スマトラ島",lines:[{speaker:"Delphine",text:"スマトラ島はインドネシア最大の島です。オランダ領東インドにおける最大の宝であり、日本が太平洋戦争へ踏み切った主要な理由の一つでもありました。",portrait:"portraits/investigator.png"}]},STUKAS:{title:"シュトゥーカ",lines:[{speaker:"Delphine",text:"シュトゥーカとは、第二次世界大戦中にドイツ空軍が運用した有名な急降下爆撃機・対地攻撃機、ユンカース Ju 87 を指します。",portrait:"portraits/investigator.png"}]},TRAMP_STEAMER:{title:"不定期貨物船",lines:[{speaker:"Delphine",text:"不定期貨物船とは、南シナ海における地味ながら不可欠な働き手でした。余剰貨物を求めて港から港へ渡り歩く商船です。",portrait:"portraits/investigator.png"}]},SHOPHOUSE:{title:"ショップハウス",lines:[{speaker:"Delphine",text:"ショップハウスとは、一階が店舗、二階が居住空間となっている長屋式の建物です。1941年までには、脱出手段を待つ難民たちを少しでも多く詰め込むため、薄いベニヤ板で細かく仕切られた迷路のような内部構造になっていました。",portrait:"portraits/investigator.png"}]},ENDING_INTRO:{title:"最後の境界",lines:[{speaker:"Rose",text:"こんにちは。どのようなご用件でしょうか？",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"スターリング夫人？ ようやくお会いできて本当に嬉しいです。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"私はあなたをご存じありません。でも、私はあなたとご家族について多くを知っています。そして、ぜひ中でご説明させていただきたいのです。",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"どうぞ、お入りください。散らかっていて申し訳ありません、ちょうどテストの採点をしていたところなんです。学校教師をしておりまして。",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"ありがとうございます。",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"リュン、お客様よ！",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Lune",text:"今行くわ！",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"リュン！ 見違えたわ……なんて美しい女性になったの。",portrait:"portraits/investigator.png"},{speaker:"Lune",text:"失礼ですが……私たち、お知り合いでしたか？",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"長い話になるわ。スターリングさんはご在宅かしら？ 突然訪ねてきた理由を説明する前に、皆さん揃っていてほしいのです。",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"申し訳ありません。主人はまだ仕事中なんです。もうすぐ戻ると思います。",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"でしたら、先に少しお話ししましょうか。私が本当に会いに来た相手は、この部屋にいるのですから。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"リュン、あなたにどうしても伝えなければならない大切なことがあります。",portrait:"portraits/investigator.png",action:"show_ending_choice"}]},ENDING_1:{title:"明かされた真実",lines:[{speaker:"Delphine",text:"あなたのお兄様は生きています……グッドウィルさん。",portrait:"portraits/investigator.png"},{speaker:"Lune",text:"えっ？ な、何を……何を言っているの？ どうして私の……？ そんなはずないわ。",portrait:"portraits/lune_older.png"},{speaker:"Rose",text:"あなたは一体何者なの？ なぜそんな酷いことを言うのです？ 私たちはもう十分に苦しみ、悲しんできたのよ！",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"申し訳ありません。本当に申し訳ありません。突然のことで混乱されるのも当然です。でも……証拠があります。どうか、この手紙を読んでください。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"私は……“感応者”なのです。過去の残響を見ることができます。そしてあなたのお兄様から、あなたとお父様に何が起きたのかを調べてほしいと依頼されました、リュン。彼は、あのボルネオの夜にあなたも亡くなったと思っていたのです。そうでなければ、もっと近くを探していたでしょう。",portrait:"portraits/investigator.png"},{speaker:"Lune",text:"でもルーカスは……",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"彼はあなたに嘘をついていました、リュン。お二人に対してです。理由はわかりません。でも、この数年間ずっと真実を隠し続けていた。",portrait:"portraits/investigator.png"},{speaker:" ",text:"ルーカスが家に入ってくる。"},{speaker:"Lucas",text:"な……何が起きているんだ？",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:" ",text:"ローズがルーカスへ手紙を投げつける。"},{speaker:"Rose",text:"いつ話すつもりだったの？ それとも、一生黙っているつもりだった？ どうしてこんなことができたの、あなた？",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:" ",text:"ルーカスが手紙を読む。"},{speaker:"Lucas",text:"僕は……本当にすまない。君たちを失いたくなかったんだ。この生活も失いたくなかった。愛しているんだ。二人とも、本当に愛している。",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Lune",text:"わからないわ。愛していると言いながら、どうしてこんなにも私を傷つけられるの？ 父と母を失ったことで私がどれほど苦しんだか、あなたは知っていたでしょう？ それなのに、兄まで殺したことにしたの？",portrait:"portraits/lune_older.png"},{speaker:"Lucas",text:"君を失うのが怖かったんだ。彼は本当のお兄さんだ！ 成功していて、お金もあって……僕なんか何者でもない。君たち二人に相応しくない。",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Rose",text:"じゃあ私は？ 私たちはどうなるの？ そんなことをしたら、私たちがどうなると思ったの？",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Lucas",text:"なぜ君が僕を愛してくれるのか、今でもわからないんだ、ローズ。いつか君が正気に戻って僕を捨てるんじゃないかと、ずっと怯えていた。そしてリュンがいなければ、もうとっくにそうしていたんじゃないかって。君はただ都合がいいから僕といるだけなんじゃないかって思っていた。君は僕なんかより、もっと良い相手を選べたはずだ。",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Rose",text:"あなた、おかしいわ。私はルーカスを選んでいた。百の部屋でも、百の人生でも、私はあなたを選んでいた。愛していたのよ。",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Rose",text:"でも、もう……",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Rose",text:"デルフィーヌ。リュンのお兄様に会わせてくださる？……今すぐに。",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"ええ、もちろんです。",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"リュン？",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Lune",text:"本当に愛していたの。私たちの家族を、本当に大切に思っていた。あなたは私の心を壊したわ、ルーカス。満足でしょうね。",portrait:"portraits/lune_older.png"},{speaker:" ",text:"リュンは首からネックレスを引きちぎる。真珠が部屋中へ飛び散った。"},{speaker:"Lune",text:"準備はできているわ。",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"参りましょう。彼はここからそう遠くないカフェで待っています。",portrait:"portraits/investigator.png"},{speaker:" ",text:"彼女たちが去っていくのを、ルーカスは一言も発さず見送っていた。ただその場に立ち尽くし、抑えきれず涙を流している。"},{speaker:" ",text:"終幕。",action:"credits"}]},ENDING_2:{title:"彼岸からの伝言",lines:[{speaker:"Delphine",text:"リュン、正気を疑われるでしょうけれど……私は“感応者”と呼ばれる存在なのです。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"過去の残響や、まだこの世を去りきれない魂を感じ取ることができます。いわば幽霊ですね。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"あなたのお兄様が……本当のお兄様が、私に接触してきたのです……。",portrait:"portraits/investigator.png"},{speaker:"Lune",text:"えっ？ な、何を……何を言っているの？ どうして私の……？ そんなはずないわ。",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"死後の世界からです。あなたに何が起きたのかを知るまで、彼の魂は安らげなかった。",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"あなたは何者なの？ なぜそんな酷いことを言うのです？ 私たちはもう十分に苦しみ、悲しんできたのよ！",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"申し訳ありません。本当に申し訳ありません。突然のことで衝撃的でしょうし……証拠と呼べるものも、この日誌しかありません。あのボルネオの運命の夜以来、あなたたちに起きたすべてを書き記したものです。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"もし私に今お話ししているような力がなければ、どうしてこんなことを知り得たでしょう？",portrait:"portraits/investigator.png"},{speaker:" ",text:"ローズとリュンは日誌をめくる。その顔は、自分たちの人生が記されていることへの衝撃で真っ白になっていく。"},{speaker:"Rose",text:"どうしても理解が追いつかないわ……彼はどうやってあなたに接触したの？",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"私は手紙を受け取ったと思っていました。でも、あれは本当の意味では現実のものではなかったのです。考えてみれば、気づくべきでした。あの手紙には、当時農園にいた全員の写真が同封されていましたから。たとえば、どうやって彼がカナンやアイシャの写真を手に入れられたというのでしょう……？",portrait:"portraits/investigator.png"},{speaker:" ",text:"ローズとリュンは、信じられないという表情でデルフィーヌを見つめている。"},{speaker:"Delphine",text:"自分でも途方もない話だとはわかっています。本当に。ここへ来るべきかどうか、長い間悩みました。",portrait:"portraits/investigator.png"},{speaker:" ",text:"ルーカスが家へ入ってくる。"},{speaker:"Lucas",text:"な……何が起きているんだ？",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:" ",text:"リュンは駆け寄り、泣きながら彼に強く抱きつく。"},{speaker:"Rose",text:"リュンの……お兄様の話よ。この人、自分は彼と話したと言うの。",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"いえ、違います。話したとは言っていなくて、私は……",portrait:"portraits/investigator.png"},{speaker:"Lucas",text:"君は感応者なのか？ 待ってくれ……君、デルフィーヌか？",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Delphine",text:"ええ。私たち、以前にお会いしていましたか？",portrait:"portraits/investigator.png"},{speaker:"Lucas",text:"いや、直接ではない。でもMI6が以前、君を雇っていたんだ。君は我々のために……そして国のために、素晴らしい働きをしてくれた。本当に感謝している。",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Delphine",text:"ありがとうございます。そう言っていただけると救われます。",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"待って。じゃあ、この人の言っていることは全部本当なの？",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Lucas",text:"僕がこれまで見聞きしてきたことを思えば、彼女の言葉を疑う気にはなれない。",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:" ",text:"最初の衝撃から立ち直ったリュンが、ようやく口を開く。"},{speaker:"Lune",text:"つまり兄は、私のことをそれほどまでに想っていて、真実を知るまで旅立つことができなかった……そういうこと？",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"ええ、そういうことです。そして、あなたが生きていて、幸せに人生を歩んでいると知った瞬間、彼が私へ送った手紙の残響は消え去り、彼が去っていくのを感じました。ようやく安らぎを得たのです。",portrait:"portraits/investigator.png"},{speaker:" ",text:"気まずいほど長い沈黙が部屋を包む。"},{speaker:"Rose",text:"お茶！ まあ失礼したわ。お茶でもいかが？",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"ぜひいただきたいです。",portrait:"portraits/investigator.png"},{speaker:" ",text:"皆、居間に腰を下ろす。"},{speaker:"Delphine",text:"私は……正しい選択をしたのでしょうか？ ここへ来て。本当は、何も知らないまま幸せに暮らさせてあげるべきだったのでしょうか？",portrait:"portraits/investigator.png"},{speaker:" ",text:"リュンが涙を拭う。それは喜びの涙だった。"},{speaker:"Lune",text:"正しい選択だったわ、デルフィーヌ。本当の意味で区切りをつけることができたもの。ありがとう。",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"ああ、それと忘れるところでした！",portrait:"portraits/investigator.png"},{speaker:" ",text:"デルフィーヌがポケットから何かを取り出す。"},{speaker:"Delphine",text:"実はここへ来る前に、セヴィル嬢に会ってきたんです。本当に来るべきかどうか、少し確かめたくて。",portrait:"portraits/investigator.png"},{speaker:"Lucas",text:"おや、シンシアは今この国にいるのか？",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Delphine",text:"ええ、でもほんの短い滞在ですし、すべて極秘扱いです。居場所を知っている人間はほとんどいません。でも……まあ、私は少々特別な手段がありますので。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"ともかく、リュン。彼女からこれを預かっています。",portrait:"portraits/investigator.png"},{speaker:" ",text:"デルフィーヌは、たった一粒の赤い真珠をリュンへ手渡す。"},{speaker:"Delphine",text:"《忘れぬための形見として》――彼女はそう言っていました。",portrait:"portraits/investigator.png"},{speaker:" ",text:"リュンはその赤い真珠を、自分のネックレスの正面へ取り付ける。彼女の顔には、晴れやかな笑みが浮かんでいた。"},{speaker:" ",text:"終幕。",action:"credits"}]},ROOM_EPIPHANY:{title:"残響の終着点",lines:[{speaker:"Delphine",text:"直感が告げている。この場所で見るべきものは、もうすべて見届けたのだと。残された時間には、もはや隠された秘密はない。",portrait:"portraits/investigator.png"}]},BOAT_TUTORIAL:{title:"ボートハウス",lines:[{speaker:"Delphine",text:"つまりジェレマイアは、カナンがボートハウスでルーカスを尋問していると言っていた。なら、ジェレマイアが電話をかける前から、すでにあのやり取りは始まっていたはずね。",portrait:"portraits/investigator.png"},{speaker:" ",text:"デルフィーヌがルーカスとカナンを選択し、15:00に集中すれば、そのやり取りの残響を発見できるはずです。"},{speaker:" ",text:"タイムライン上の赤い吹き出しの数字はヒントです。そのシーン内に、まだ発見していないイベントの手がかりがいくつ残っているかを示しています。"},{speaker:" ",text:"ルーカスとカナンのやり取りを発見することで、16:00の書斎に表示されていたヒント数は「2」から「1」に減少します。"}]},BOAT_TUTORIAL_EMPTY:{title:"ボートハウス",lines:[{speaker:"Delphine",text:"ここで残響を解き明かすには、まだ情報が足りない。招待客名簿を見直して、何人かの正体を突き止める必要があるわね。",portrait:"portraits/investigator.png"}]},TIDAK_APA:{title:"ティダッ・アパ",theme:"jargon",lines:[{speaker:"Delphine",text:"“Tidak apa” はマレー語で「気にするな」「問題ない」という意味です。",portrait:"portraits/investigator.png"}]},CYNTHIA_JOURNEY:{title:"シンシアの旅路",lines:[{speaker:"Delphine",text:"シンシアの旅がどうなったのか、気になるわね。私の依頼人はその情報を必要とも望んでもいないでしょうけれど、セヴィル嬢はまだ私にとって有用な存在になり得る。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"少し彼女の様子を探ってみるべきかもしれない。集中すれば、心の眼で彼女の旅路を感じ取れる気がする。",portrait:"portraits/investigator.png"}]},MANIFEST:{lines:[{speaker:"Delphine",text:"主要人物たちの写真がある。感じ取れる残響から、どの人物が重要になるかはわかるわ。事件ファイルに追加しておきましょう。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"彼らを感じ取れるのは水曜日の朝8時以降だけね。それ以前は発進艇が農園から遠すぎたのでしょうし、そもそも海のどこから現れたのかも特定できなかった。",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"それに、8時の時点では全員が岸辺に集まっていて、その後それぞれ別行動を取り始めたこともはっきり感じられる。",portrait:"portraits/investigator.png"}]},PEARL_2:{lines:[{speaker:"Delphine",text:"品物の持ち主というのは、時に当てにならないことがある。この真珠は本来ならボーンかジェレマイアの所有物であるはずだけれど、長い間シンシアのもとにあったせいで、彼女の残滓が深く染みついているの。",portrait:"portraits/investigator.png"}]},SAMPAN:{lines:[{speaker:"Delphine",text:"現地で使われている丸木舟。",portrait:"portraits/investigator.png"}]},PARANG:{lines:[{speaker:"Delphine",text:"熱帯地域を象徴する実用刀であり武器。密生した硬いジャングル植物を切り払うために特化して作られている。",portrait:"portraits/investigator.png"}]},CHARLESBROOKE:{lines:[{speaker:"Delphine",text:"チャールズ・ブルック……その名前、どこかで見覚えがある。以前どこで目にしたのだったかしら？ ボルネオについて調べていた時に見かけた気がする。もしかすると植民地関連の用語集だったかも。",portrait:"portraits/investigator.png"}]},WHITERAJAH:{lines:[{speaker:"Delphine",text:"そうだ、これだわ！ 白人王よ！ しかも写真まであるなんて、なんて都合がいいのかしら。",portrait:"portraits/investigator.png",trigger:"reveal:p21"}]},IBAN:{lines:[{speaker:"Delphine",text:"イバンの戦士たちは、マレー諸島でもっとも伝説的かつ恐れられた戦士として知られていた。イギリスやオランダが蒸気船や電信を持ち込む一方で、イバン族はなおボルネオの大地を支配する存在であり続けた。彼らの文化は河川と密林戦の伝統の上に築かれていたの。",portrait:"portraits/investigator.png"}]},DUSUN:{lines:[{speaker:"Delphine",text:"ドゥスン族は北ボルネオ最大の先住民族であり、農耕民であると同時に、獰猛な狩人としても知られている。",portrait:"portraits/investigator.png"}]},BATU:{title:"バトゥ・サピ",lines:[{speaker:"Delphine",text:"バトゥ・サピはサンダカン沿岸部の地域で、浸食によって形成された三本脚の水牛のような岩で知られている。カラムンティンの海岸近くに位置するこの奇岩には伝説が残されており、村を救うためワニと戦った英雄的な水牛が姿を変えたものだと信じられている。",portrait:"portraits/investigator.png"}]},JUBILEE:{lines:[{speaker:"Delphine",text:"サンダカン・ジュビリー時計塔は、サンダカンに存在した歴史的建造物だった。イギリス領北ボルネオ植民地時代を象徴する名所の一つであり、戦争を生き延びたものの、町の再建後まもなく取り壊されてしまった。",portrait:"portraits/investigator.png"}]},CHINESETOWN:{lines:[{speaker:"Delphine",text:"チャイナタウンはサンダカン商業の中心地であり、ショップハウスや市場が立ち並ぶ活気ある地区だった。現地華人社会が商売を営む場所で、商人たちの声と香辛料の匂いに満ちた、賑やかな活動の拠点だったの。",portrait:"portraits/investigator.png"}]},BARRAGE_BALLOONS:{lines:[{speaker:"Delphine",text:"阻塞気球は、急降下爆撃機からロンドンを防衛するために使用されていた。水素を充填した気球を鋼鉄製ケーブルで地上へ繋ぎ止め、敵機をより高高度へ追いやることで爆撃精度を低下させる目的があったの。",portrait:"portraits/investigator.png"}]},MIND_EYE:{lines:[{speaker:"Delphine",text:"心の眼に何かが引っかかった。調べてみるべきね。",portrait:"portraits/investigator.png"}]},CYNTHIA_ENDING:{lines:[{speaker:" ",text:" ",action:"credits"}]},POST_CREDITS:{lines:[{speaker:" ",text:"1964年2月"},{speaker:" ",text:"玄関のドアを叩く音がする。"},{speaker:"Delphine",text:"こんな時間に誰かしら？",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"今行きます！",portrait:"portraits/investigator.png"},{speaker:"Cynthia",text:"こんにちは、デルフィーヌ。",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"Delphine",text:"セヴィル捜査官？ どうしてここへ？",portrait:"portraits/investigator.png"},{speaker:"Cynthia",text:"私は危険な状況にいるの。そして、もう誰を信じればいいのかわからない。あなたの助けが必要なの。",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"Delphine",text:"何があったの？ 一体どういうこと？",portrait:"portraits/investigator.png"},{speaker:"Cynthia",text:"私たちの優秀なエージェントの一人で、私にとっても大切な友人が行方不明になったの。",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"Cynthia",text:"最後に話した時、彼は“大きな何か”を掴みかけていると言っていた。でも、誰かにつけられているとも。",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"Cynthia",text:"心配でたまらない。でも最悪の事態を恐れている。そして、内部の誰かが関わっている気がしてならないの。",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"Delphine",text:"それはお気の毒に……。その人の名前は？",portrait:"portraits/investigator.png"},{speaker:"Cynthia",text:"彼の名前はアーサー。アーサー・バードホイッスルよ。",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:" ",text:" ",action:"tbc"}]}};export{e as DIALOGUE};
